assignments.value:
={{ (() => {
const platform = $('workflow_trigger').item.json.platform || 'twitter';
const configs = {
  twitter: {
    name: 'Twitter/X',
    charLimit: 280,
    format: 'Thread of numbered tweets (1/, 2/, etc.). Each tweet max 280 chars. Use line breaks for readability. Emojis sparingly. Include relevant @mentions. End with engagement CTA.',
    example: '1/ Big news in sci-fi this week...\n\n2/ [Story point with detail]\n\n3/ [Another story point]\n\nWhat do you think? Reply with your take.'
  },
  linkedin: {
    name: 'LinkedIn',
    charLimit: 3000,
    format: 'Single post, max 3000 chars. Professional tone. Use line breaks every 1-2 sentences. Hook in first line. Include 3-5 relevant hashtags at end. No emojis in body.',
    example: 'The future of [topic] is changing fast.\n\nHere\'s what caught my attention this week:\n\n[Key points with analysis]\n\n#ScienceFiction #WritingCommunity'
  },
  instagram: {
    name: 'Instagram',
    charLimit: 2200,
    format: 'Caption style, max 2200 chars. Conversational tone. Hook first line. Use paragraph breaks. 20-30 relevant hashtags in a separate block at the end. Include a CTA (save this, share, comment).',
    example: 'This blew my mind. \ud83e\udde0\n\n[Engaging summary]\n\nSave this for later \u2b07\ufe0f\n\n.\n.\n.\n#SciFi #Books #WritingCommunity'
  }
};
return JSON.stringify(configs[platform] || configs.twitter);
})() }}

